import{_ as t,o as r,c as n,ak as s}from"./chunks/framework.D3PFo-vo.js";const u=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"chinese/文言断句.md","filePath":"chinese/文言断句.md"}'),l={name:"chinese/文言断句.md"};function e(g,o,a,i,c,d){return r(),n("div",null,[...o[0]||(o[0]=[s('<h2 style="text-align:center;font-size:30px;">文言断句</h2><ul><li><h4 id="基本信息" tabindex="-1">基本信息 <a class="header-anchor" href="#基本信息" aria-label="Permalink to &quot;基本信息&quot;">​</a></h4><ul><li>文言文断句题，题号为第10小题，分值为3分，题型主要有两种：客观选择题和主观断句题。2023年以前往往采用客观选择题的形式，2023年教育部教育考试院命制的四省联考语文试题中，将断句题改为主观断句题形式。自此，2023年至2026年高考断句题型全部为主观题型。但无论是哪种题型，其解题的思路及基本方法都是一样的。</li><li>选择题题干表述一般为：   <code>10.下列对文中画波浪线部分的断句，正确的一项是（3分）。</code></li><li>主观题题干表述一般为：   <code>10.材料中画波浪线的部分有三处需要断句，请用铅笔将答题卡上相应位置的答案标号涂黑，每涂对一处给1分，涂黑超过三处不给分。（3分）</code></li></ul></li><li><h3 id="解题思路" tabindex="-1">解题思路 <a class="header-anchor" href="#解题思路" aria-label="Permalink to &quot;解题思路&quot;">​</a></h3><ul><li><h4 id="一-通读文章初判断" tabindex="-1">一.通读文章初判断 <a class="header-anchor" href="#一-通读文章初判断" aria-label="Permalink to &quot;一.通读文章初判断&quot;">​</a></h4>    先通读所给语句的<strong>前后语境</strong>，弄懂<strong>上下文</strong>的意思，疏通文言文的<strong>基本情节</strong>，若有人物对话，要<strong>弄清说话的人物是谁，讲的主要内容是什么</strong>。通过对文意的了解，初步判断选项中易切分的地方。</li><li><h4 id="二、明确成分意连贯" tabindex="-1">二、明确成分意连贯 <a class="header-anchor" href="#二、明确成分意连贯" aria-label="Permalink to &quot;二、明确成分意连贯&quot;">​</a></h4>   在基本了解文意的基础上，根据词性明确句中<strong>主谓宾</strong>的成分。 <ul><li><strong>①</strong>文言文中的名词和代词常用来作主语和宾语，断句时可先找出<strong>名词</strong>，如<code>人名</code>、<code>地名</code>、<code>官名</code>、<code>国名</code>、<code>朝代名</code>、<code>器物名</code>、<code>动物名</code>等；也可先找出<strong>代词</strong>，如<code>吾</code>、<code>予</code>、<code>余(表示“我”)</code>、<code>尔</code>、<code>汝(女)</code>、<code>公</code>、<code>卿</code>、<code>君</code>、<code>若(表示“你”)</code>、<code>其</code>、<code>彼</code>、<code>此</code>、<code>之</code>等。这些词如果作主语，那么它的前面就可能断句；如果作宾语，那么它的后面也可能断句。</li><li><strong>②</strong>承担一个句子谓语成分的是<strong>动词、形容词</strong>，断句时，可以先找到语句中的这类词，确定为谓语；然后根据谓语前的状语、主语和谓语后的宾语等来断定语句的停顿点。</li><li><blockquote><p>【例句1】夫<strong>鲁国</strong>有患者<strong>君臣父子</strong>皆被其辱祸及众庶<strong>妇人</strong>独安所避乎</p></blockquote></li><li><blockquote><p>【例句2】<strong>刘备</strong>为<strong>吕布</strong>所袭奔于<strong>操程昱</strong>以<strong>备</strong>有雄才劝<strong>操</strong>图之</p></blockquote></li><li><blockquote><p>【例句3】夫为人所陷而欲胜敌不亦难乎<strong>臣</strong>故曰无术焉<strong>苻坚</strong>之类是也</p></blockquote></li></ul></li><li><h4 id="三、巧抓标志定关键" tabindex="-1">三、巧抓标志定关键 <a class="header-anchor" href="#三、巧抓标志定关键" aria-label="Permalink to &quot;三、巧抓标志定关键&quot;">​</a></h4><ul><li><h5 id="一-词语标志" tabindex="-1">（一）词语标志 <a class="header-anchor" href="#一-词语标志" aria-label="Permalink to &quot;（一）词语标志&quot;">​</a></h5><ul><li><h6 id="曰-云-言-对话最易被发现" tabindex="-1"><strong>“曰”“云”“言”</strong>，对话最易被发现 <a class="header-anchor" href="#曰-云-言-对话最易被发现" aria-label="Permalink to &quot;**“曰”“云”“言”**，对话最易被发现&quot;">​</a></h6>   文言文在叙述人物的对话时，经常用“曰”“云”“言”等字，遇到这些字，我们很容易根据上下文判断出说话人以及所说的内容，<strong>但这些字的后面是否需要断开，要结合语境判断</strong>。 <ul><li><blockquote><p>【例句1】母异之谓族人<strong>曰</strong>/<code>（有明确说话主体、内容）</code>是儿爱我如此多知孝养我矣</p></blockquote></li><li><blockquote><p>【例句2】夫为人所陷而欲胜敌不亦难乎/臣故<strong>曰</strong><code>（表达观点态度）</code>无术焉/苻坚之类是也</p></blockquote></li><li><blockquote><p>【例句3】韩非书<strong>云</strong><code>（转述书中观点）</code>夫子善之/引以张本然后难之岂有不似哉</p></blockquote></li></ul></li><li><h6 id="常用虚词" tabindex="-1"><strong>常用虚词</strong> <a class="header-anchor" href="#常用虚词" aria-label="Permalink to &quot;**常用虚词**&quot;">​</a></h6>   文言虚词的主要作用是<strong>表示语法关系和表达语气</strong>，所以虚词是明辨句读的重要标志，在断句中，具体要关注以下几类虚词： <ul><li><h6 id="_1句首发语词" tabindex="-1">①句首发语词： <a class="header-anchor" href="#_1句首发语词" aria-label="Permalink to &quot;①句首发语词：&quot;">​</a></h6> “<strong>盖、唯、盍、夫、且夫（况且，再说）、若夫（至于）、至若（至于）</strong>”等<strong>前面</strong>可断句，如“<strong>嗟夫</strong>”、“<strong>嗟乎</strong>”、“<strong>呜呼</strong>”等，<strong>前后都可</strong>断句；</li><li><h6 id="_2句末语气词" tabindex="-1">②句末语气词: <a class="header-anchor" href="#_2句末语气词" aria-label="Permalink to &quot;②句末语气词:&quot;">​</a></h6> “<strong>也、矣、耶、哉、乎、焉、兮、耳、而已</strong>”等<strong>后面</strong>可断句</li><li><h6 id="_3关联词" tabindex="-1">③关联词： <a class="header-anchor" href="#_3关联词" aria-label="Permalink to &quot;③关联词：&quot;">​</a></h6> “<strong>虽</strong>”“<strong>苟</strong>”“<strong>纵</strong>”“<strong>是故</strong>”“<strong>于是</strong>”“<strong>向使</strong>”“<strong>然而</strong>”“<strong>无论</strong>”“<strong>至若</strong>”“<strong>是以</strong>”“<strong>继而</strong>”“<strong>纵使</strong>”“<strong>然则（既然这样，那么）</strong>”等<strong>前面</strong>大多可以断句；</li><li><h6 id="_4时间词" tabindex="-1">④时间词： <a class="header-anchor" href="#_4时间词" aria-label="Permalink to &quot;④时间词：&quot;">​</a></h6> “顷之（不久）”“向之（刚才）”“未几（不久）”“已而”“斯须（极短时间）”“既而（不久）”“俄而（不久）”等，也可以帮助断句。</li><li><h6 id="_5疑问语气词" tabindex="-1">⑤疑问语气词： <a class="header-anchor" href="#_5疑问语气词" aria-label="Permalink to &quot;⑤疑问语气词：&quot;">​</a></h6> “何、胡、安、曷、奚、盍、孰、焉”等表示句子的语气,前后可断。</li><li><h6 id="_6表谦敬的词" tabindex="-1">⑥表谦敬的词： <a class="header-anchor" href="#_6表谦敬的词" aria-label="Permalink to &quot;⑥表谦敬的词：&quot;">​</a></h6> “窃（私下）、请（请允许我）、谨（恭敬地）、敢（冒昧地）”这些词常用在一句话的开头，有领起全句的作用，前面可断句。</li><li>例句 <ul><li>【例句1】为将而降降而为之效死以战<strong>虽</strong>欲浣涤其污而已缁之素不可复白</li><li>【例句2】韩非书云夫子善之引以张本<strong>然后</strong>难之<strong>岂</strong>有不似哉</li><li>【例句3】而举朝之众倾心前人之弊未尽往往拟议<strong>愚</strong>用惜焉 （译文：满朝文武官员无不拥护于您，前朝的弊端还没有全都革除，常常有怀疑的议论，我因之感到惋惜。）</li><li>【注意】<strong>抓虚词判断句子停顿时要注意灵活性。</strong><ul><li>（1）“也”若用在句间，表句间语气舒缓，诵读时不能停顿，其后不能断句。 如：<strong>其闻道也亦先乎吾</strong>。</li><li>（2）“乎”有时用在句中同“于”，作介词，其后不能断句。如：<strong>生乎吾前</strong>。</li></ul></li></ul></li></ul></li><li><h6 id="相同词语" tabindex="-1"><strong>相同词语</strong> <a class="header-anchor" href="#相同词语" aria-label="Permalink to &quot;**相同词语**&quot;">​</a></h6> 古文中两个相同词语连用，如果不属于形容词、名词的重叠形式，一般来说，它们分属两句话，应当从中间断开。 <ul><li>【例句1】为将而<strong>降</strong>/<strong>降</strong>而为之效死以战虽欲浣涤其污而已缁之素不可复白</li><li>【例句2】则好赏恶罚之人释公<strong>行</strong>/<strong>行</strong>私术比周以相为也</li></ul></li><li><h6 id="固定词语" tabindex="-1"><strong>固定词语</strong> <a class="header-anchor" href="#固定词语" aria-label="Permalink to &quot;**固定词语**&quot;">​</a></h6><strong>文言文中那些固定搭配的词语，不要把它们拆散</strong>，可以减少断句失误。如“<strong>有所</strong>（有…… 的人/事/物）”“<strong>无所</strong>（没有…… 的人/事/ 物）”“<strong>有以</strong>（有用来）”“<strong>无以</strong>（没有用来……；无法）”“<strong>以为</strong>（认为；把……当作）”“<strong>何所</strong>（表疑问的固定结构，是“所……者为何”的倒装和压缩，可译为“所……的（人、事、物）是什么”）”“<strong>孰若</strong>”“<strong>至于</strong>”“<strong>足以</strong>”“<strong>得无</strong>（恐怕、莫非）”“<strong>无乃</strong>（恐怕、莫非）”“<strong>何以</strong>”“<strong>于是</strong>”“<strong>然则</strong>”“<strong>何如</strong>”“<strong>奈何</strong>”“<strong>孰与</strong>”等。 <ul><li>【例句】是以老而无妻子者/<strong>有所</strong>侍养以终其寿/幼弱孤童之无父母者/<strong>有所</strong>放依以长其身</li></ul></li></ul></li><li><h4 id="二-句式标志" tabindex="-1">（二）句式标志 <a class="header-anchor" href="#二-句式标志" aria-label="Permalink to &quot;（二）句式标志&quot;">​</a></h4> 文言文中的特殊句式和固定句式都可以作为断句的切入点。常见特殊句式： <ul><li>判断句：“<strong>……者，……也</strong>”“<strong>为、乃、即、则</strong>”</li><li>被动句：“<strong>为……所……</strong>”“<strong>受……于……</strong>”“<strong>见……于……</strong>”</li><li>反问句：“<strong>不亦……乎</strong>”“<strong>孰与……乎</strong>”“<strong>其……乎</strong>”“<strong>安……哉</strong>”“<strong>何……为</strong>”</li><li><h5 id="_1-固定句式" tabindex="-1">1.固定句式： <a class="header-anchor" href="#_1-固定句式" aria-label="Permalink to &quot;1.固定句式：&quot;">​</a></h5> “<strong>况……乎</strong>”“<strong>何(以)……为</strong>”“<strong>何……之有</strong>” <code>(何罪之有?)</code> “<strong>如……何</strong>”<code>（如太行王屋何？）</code>“<strong>唯……是……</strong>”<code>（唯余马首是瞻）</code>“<strong>非惟……抑亦……</strong>”<code>（非惟天时，抑亦人谋）</code>“<strong>不亦……乎</strong>”（<code>不亦说乎？）</code> “<strong>何……之为</strong>”<code>（秦则无礼，何施之为？）</code>“<strong>无乃……乎</strong>”<code>（无乃不可乎？）</code>“<strong>可得……欤</strong>”<code>（可得闻欤？）</code>“<strong>得无……乎</strong>”<code>（得无异乎？）</code><ul><li>例句： <ul><li><blockquote><p>【例句1】魏君<strong>贤人是礼</strong>国人称仁上下和合未可图也</p></blockquote></li><li><blockquote><p>【例句2】刘备<strong>为</strong>吕布<strong>所</strong>袭奔于操程昱以备有雄才劝操图之</p></blockquote></li><li><blockquote><p>【例句3】君遇之无礼彼<strong>若</strong>有时反国而起兵<strong>即</strong>恐为曹伤君不如杀之</p></blockquote></li></ul></li></ul></li><li><h5 id="_2-修辞句式-排比、对称与反复" tabindex="-1">2.修辞句式：排比、对称与反复 <a class="header-anchor" href="#_2-修辞句式-排比、对称与反复" aria-label="Permalink to &quot;2.修辞句式：排比、对称与反复&quot;">​</a></h5> 古人写文章，十分讲究对仗工整，讲究对应，讲究互相照应，好用对偶（对称）句、排比句、反复句、顶真句，这也为我们正确断句提供了条件。我们利用这一特点进行断句，常常是断开一处，接着便可断开几处，收到事半功倍的效果。 <ul><li><blockquote><p>【例句1】是故<strong>礼以将其力</strong>/<strong>敬以入其忠</strong>饮食移味居处温愉</p></blockquote></li><li><blockquote><p>【例句2】由是<strong>父得生于法之外</strong>/<strong>法得伸于死之余</strong>故曰贞夫法哉义斯当矣</p></blockquote></li></ul></li></ul></li></ul></li><li><h4 id="四-放回语境顺一遍" tabindex="-1">（四）放回语境顺一遍 <a class="header-anchor" href="#四-放回语境顺一遍" aria-label="Permalink to &quot;（四）放回语境顺一遍&quot;">​</a></h4> 将断好的句子，放回到原文语境中，再读一遍，看看语意是否通顺、连贯、合理。 <ul><li>**【注意】**无论是主观题还是选择题，都可以借助其所给的信息进行快速断定。若是主观题，重点品析其所给出的断句处；若是客观题，可将四个选项进行比对，将相同断句的部分作为理解句意的抓手，勾画出断句不同的地方，重点比对选项的不同断点。</li></ul></li></ul></li></ul>',2)])])}const b=t(l,[["render",e]]);export{u as __pageData,b as default};
